defmodule SessionManager.Plug do
  @moduledoc """
  Plug for integrating SessionManager into a Phoenix pipeline.
  Reads session from cookie, validates it, and makes it available in conn.assigns.
  """

  import Plug.Conn
  @behaviour Plug

  @cookie_name "_app_session"
  @cookie_opts [
    http_only: true,
    secure: true,
    same_site: "Strict",
    max_age: 86_400,
    path: "/"
  ]

  @impl true
  def init(opts), do: opts

  @impl true
  def call(conn, _opts) do
    conn = fetch_cookies(conn)

    case Map.get(conn.cookies, @cookie_name) do
      nil ->
        assign(conn, :session_data, %{})

      cookie_value ->
        case SessionManager.load_session(cookie_value) do
          {:ok, session_data} ->
            conn
            |> assign(:session_data, session_data)
            |> register_before_send(&persist_session/1)

          {:error, _reason} ->
            # Invalid/expired/tampered session — clear it
            conn
            |> delete_resp_cookie(@cookie_name, @cookie_opts)
            |> assign(:session_data, %{})
        end
    end
  end

  @doc """
  Sets session data on the connection. The session will be persisted
  to the cookie in the before_send callback.
  """
  def put_session_data(conn, key, value) when is_binary(key) do
    current = conn.assigns[:session_data] || %{}
    updated = Map.put(current, key, value)

    conn
    |> assign(:session_data, updated)
    |> assign(:session_dirty, true)
  end

  @doc """
  Creates a new session and sets the cookie on the connection.
  """
  def create_new_session(conn, session_data) when is_map(session_data) do
    case SessionManager.create_session(session_data) do
      {:ok, cookie_value} ->
        conn
        |> put_resp_cookie(@cookie_name, cookie_value, @cookie_opts)
        |> assign(:session_data, session_data)

      {:error, _reason} ->
        conn
    end
  end

  @doc """
  Destroys the current session.
  """
  def destroy_session(conn) do
    conn
    |> delete_resp_cookie(@cookie_name, @cookie_opts)
    |> assign(:session_data, %{})
    |> assign(:session_dirty, false)
  end

  defp persist_session(conn) do
    if conn.assigns[:session_dirty] do
      session_data = conn.assigns[:session_data] || %{}

      case SessionManager.create_session(session_data) do
        {:ok, cookie_value} ->
          put_resp_cookie(conn, @cookie_name, cookie_value, @cookie_opts)

        {:error, _reason} ->
          conn
      end
    else
      conn
    end
  end
end